#!/usr/bin/env python3
"""Deterministic local builder for the 11 July 2026 Harry P3 + ESAT multi-step pack.
Source boundary: the passed final guide/evidence only.  It intentionally omits P3 Q1:
the passed guide says it was discussed only and does not retain a verbatim complete prompt.
"""
from __future__ import annotations
import shutil
from pathlib import Path
import matplotlib
matplotlib.use("Agg")
import matplotlib.pyplot as plt
from matplotlib.patches import Circle, Ellipse, Rectangle
import numpy as np

ROOT = Path(__file__).resolve().parent
SRC_MJ = Path("/root/agent-artifacts/workspace/revision_pipeline/lessons/2026-07-11_harry_p3_esat/multistep/mathjax-tex-svg.js")
BLUE, RED, GREEN, GREY, INK = "#2563eb", "#dc2626", "#15803d", "#94a3b8", "#172033"

CSS = r'''
:root{--ink:#111827;--muted:#5b6473;--paper:#fff;--canvas:#f3f5f8;--line:#d8dee8;--work:#e5e7eb;--accent:#0f766e;--accent-pale:#e7f5f2;--trap:#9f1239;--source:#334155;--radius:12px}*{box-sizing:border-box}html{background:var(--canvas)}body{margin:0;color:var(--ink);font:15px/1.53 -apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:var(--canvas)}#card{max-width:1180px;margin:0 auto;padding:28px 28px 52px}.export-btn{position:fixed;top:16px;right:16px;z-index:100;background:#111827;color:#fff;text-decoration:none;padding:8px 16px;border-radius:8px;font-weight:700;font-size:12px;box-shadow:0 3px 10px #0003}.kicker{font-size:11px;font-weight:800;letter-spacing:.11em;text-transform:uppercase;color:var(--accent);margin-bottom:6px}.q-header{background:#fff;border:1px solid var(--line);border-left:6px solid var(--accent);border-radius:var(--radius);padding:22px 24px;margin:0 0 16px;box-shadow:0 1px 2px #1111}.q-header h1{font-size:25px;line-height:1.2;margin:0 0 9px}.q-header p{margin:8px 0}.meta{display:flex;flex-wrap:wrap;gap:7px;margin:13px 0 0}.badge{display:inline-block;border:1px solid #bdd8d4;background:var(--accent-pale);color:#115e59;border-radius:999px;padding:3px 9px;font-size:12px;font-weight:700}.badge.source{background:#eef2f7;border-color:#d7dee8;color:var(--source)}.notice{background:#fffbeb;border:1px solid #fcd34d;border-radius:9px;padding:10px 12px;margin:15px 0;color:#713f12}.part{margin:18px 0;border:1px solid var(--line);border-radius:var(--radius);background:#fff;overflow:hidden}.part-title{display:flex;align-items:center;gap:9px;flex-wrap:wrap;padding:12px 16px;background:#f8fafc;border-bottom:1px solid var(--line);font-size:17px;font-weight:800}.marks{font-size:12px;color:#fff;background:#334155;border-radius:999px;padding:2px 8px}.carry-in{margin:13px 16px 0;border-left:4px solid #0f766e;background:#edf8f6;padding:9px 11px;font-size:14px}.work{margin:13px 16px 16px;background:var(--work);border:1px solid #cbd5e1;border-radius:9px;padding:15px 16px;position:relative}.work:before{content:"FINAL WORKING · mask this grey panel";display:block;color:#475569;font-size:10px;letter-spacing:.08em;font-weight:800;margin-bottom:8px}.strategy{font-weight:800;color:#0f172a}.work p{margin:8px 0}.formula{border-left:3px solid #64748b;padding-left:10px;margin:10px 0}.answer{background:#ecfdf5;border:1px solid #86efac;border-radius:8px;padding:10px 12px;font-weight:800;margin-top:11px}.why{margin:12px 16px 16px;padding:11px 13px;border-radius:8px;border:1px solid #fecdd3;background:#fff1f2;color:#4c0519}.why strong{color:var(--trap)}.q-diagram{padding:5px 16px 13px}.q-diagram figure{margin:8px auto;text-align:center}.q-diagram img{max-width:380px;width:100%;height:auto;border-radius:6px;margin:8px auto;display:block;box-shadow:0 1px 3px rgba(0,0,0,.12)}figcaption{font-size:12px;color:var(--muted);max-width:430px;margin:0 auto}.footer{font-size:12px;color:var(--muted);margin-top:18px;border-top:1px solid var(--line);padding-top:12px}.mjx-container{max-width:100%;overflow-x:auto;overflow-y:hidden}.q-header mjx-container[display="true"] svg,.work mjx-container[display="true"] svg{max-width:100%!important;height:auto!important}@media(max-width:650px){#card{padding:18px 12px 35px}.q-header{padding:17px}.q-header h1{font-size:21px}.export-btn{top:8px;right:8px}.part-title{font-size:16px}.work,.q-diagram{margin-left:10px;margin-right:10px;padding-left:12px;padding-right:12px}.carry-in{margin-left:10px;margin-right:10px}mjx-container{font-size:85%!important}}
'''

CARD_TEMPLATE = r'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>__TITLE__ · Harry 11 Jul 2026</title><script>window.MathJax={tex:{inlineMath:[["\\(","\\)"]],displayMath:[["\\[","\\]"]]},svg:{fontCache:"global"}};</script><script defer src="mathjax-tex-svg.js"></script><style>__CSS__</style></head><body><a class="export-btn" href="__PNG__" target="_blank">Export PNG</a><main id="card">__BODY__</main></body></html>'''

EXTRA = r'''<section class="part precision"><div class="part-title">Precision recall strip <span class="marks">closed-book check</span></div><div class="carry-in"><strong>Carry-in:</strong> retain the original condition, exact values, and command word before starting any algebra.</div><div class="work" data-maskable="true"><p class="strategy">Retrieve the symbolic route before substituting numbers.</p><p><strong>1. Read the command.</strong> “Show that” ends at the displayed result; “exact” forbids an early decimal; “rate” asks for a derivative; “smallest” requires checking the first valid solution.</p><p><strong>2. Formula first.</strong> Write a named formula or identity symbolically, then substitute. Relevant lesson formulae were \\(4\\pi R^2\\), \\(2\\pi r^2+2\\pi rh\\), \\(\\frac{d}{dx}a^{kx}=a^{kx}k\\ln a\\), \\(\\left(\\frac uv\\right)'=\\frac{vu'-uv'}{v^2}\\), and the R-form coefficient relations \\(R\\cos\\alpha=a,\\ R\\sin\\alpha=b\\).</p><p><strong>3. Preserve the carry-in.</strong> Treat each displayed carry-in as known while the earlier grey working is covered. State the new equation created from it rather than referring vaguely to an earlier part.</p><p><strong>4. Final check.</strong> Check signs, domain or positivity, units where applicable, and the requested rounding. Keep stored values until the final requested precision.</p><p><strong>Formula discrimination.</strong> Surface area is not volume: a closed cylinder needs two circular ends and a curved side. A logarithm model must be converted before identifying an exponential base. In a quotient, differentiate both numerator and denominator before simplifying. In an R-form question, use coefficient matching before choosing an inverse trigonometric function.</p><p><strong>Exactness discipline.</strong> A calculator value may support a final decimal, but it should not replace an exact surd, logarithm, or trigonometric angle when the question asks for an exact value. Keep \\(10^{0.05}\\), \\(\\sqrt{19}\\), and fractional multiples of \\(\\pi\\) visible until the final line.</p><p><strong>Domain discipline.</strong> A root used as a radius must be positive; an IVT conclusion needs continuity on the stated interval; a denominator declared positive can be cancelled only after that fact is stated; and a “smallest positive” trig solution must satisfy the stated domain.</p><p><strong>One-line finish.</strong> Write the requested result with its unit, interval, or qualifying condition. A correct calculation without the final conclusion can leave an exam response incomplete. <strong>Then compare:</strong> the symbolic answer should retain every requested condition and no earlier rounded approximation. <strong>Use a complete concluding sentence.</strong> State what has been established.</p></div><aside class="why"><strong>Harry's recurring lesson theme:</strong> formula recall and small details decide marks: continuity for IVT, the square in area, the quotient-rule minus sign, radians for trig, \\(\\ln\\) for base \\(e\\), and final-only rounding.</aside></section>'''

EXTRA = EXTRA.replace(chr(92) * 2, chr(92))

def header(title: str, prompt: str, total: int, status: str, source: str) -> str:
    return f'''<section class="q-header"><div class="kicker">Harry → Phuc · 11 July 2026</div><h1>{title}</h1><p>{prompt}</p><div class="meta"><span class="badge">{total} marks</span><span class="badge">{status}</span><span class="badge source">{source}</span></div></section>'''

def part(label: str, marks: int | None, carry: str, work: str, why: str = "", diagram: str = "") -> str:
    visual = f'<div class="q-diagram">{diagram}</div>' if diagram else ""
    why_html = f'<aside class="why">{why}</aside>' if why else ""
    mark_html = f'<span class="marks">{marks} marks</span>' if marks is not None else ""
    return f'''<section class="part"><div class="part-title">{label}{mark_html}</div><div class="carry-in"><strong>Carry-in:</strong> {carry}</div>{visual}<div class="work" data-maskable="true">{work}</div>{why_html}</section>'''

def fig(file: str, caption: str) -> str:
    return f'<figure><img src="diagrams/{file}" alt="{caption}"><figcaption>{caption}</figcaption></figure>'

def write_card(slug: str, title: str, body: str):
    complete_body = body + EXTRA
    (ROOT / f"{slug}.html").write_text(CARD_TEMPLATE.replace("__TITLE__", title).replace("__PNG__", f"{slug}.png").replace("__CSS__", CSS).replace("__BODY__", complete_body), encoding="utf-8")

def diagrams():
    d = ROOT / "diagrams"; d.mkdir(exist_ok=True)
    # ESAT: sphere, closed cylinder, and unrolled curved surface.
    fig_, ax = plt.subplots(figsize=(7.0,3.1), dpi=180); ax.set_xlim(0,14); ax.set_ylim(0,5); ax.axis("off")
    ax.add_patch(Circle((2,2.55),1.25,fill=False,lw=2,color=BLUE)); ax.text(2,4.15,"sphere",ha="center",weight="bold"); ax.text(2,2.55,r"$4\pi R^2$",ha="center")
    ax.add_patch(Ellipse((6,3.25),2.3,.5,fill=False,lw=1.8,color=INK)); ax.add_patch(Ellipse((6,1.15),2.3,.5,fill=False,lw=1.8,color=INK)); ax.plot([4.85,4.85],[1.15,3.25],color=INK); ax.plot([7.15,7.15],[1.15,3.25],color=INK); ax.text(6,4.15,"closed cylinder",ha="center",weight="bold"); ax.text(6,.25,r"two ends: $2\pi r^2$",ha="center",fontsize=8)
    ax.annotate("unroll curved side",xy=(8,2.2),xytext=(9.8,3.6),arrowprops=dict(arrowstyle="->",color=GREEN,lw=1.5),color=GREEN,ha="center",fontsize=8)
    ax.add_patch(Rectangle((9.1,1.1),3.5,1.7,fill=False,lw=1.8,color=RED)); ax.text(10.85,1.95,r"$2\pi r h$",ha="center"); ax.text(10.85,.6,r"width $2\pi r$, height $h$",ha="center",fontsize=8)
    fig_.tight_layout(); fig_.savefig(d/"esat_surface_area.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)
    # Q2 IVT.
    x=np.linspace(.7,2.3,400); y=(2*x*x+3*x-4)/np.exp(x)-1/x**2
    fig_,ax=plt.subplots(figsize=(5,3),dpi=180); ax.axhline(0,color="#334155",lw=.8); ax.plot(x,y,color=BLUE,lw=2,label=r"$f(x)$"); ax.scatter([1,2],[y[np.abs(x-1).argmin()],y[np.abs(x-2).argmin()]],color=RED,zorder=3); ax.annotate(r"$f(1)<0$",(1,y[np.abs(x-1).argmin()]),xytext=(.75,-1.2),arrowprops=dict(arrowstyle="->",color=RED),color=RED); ax.annotate(r"$f(2)>0$",(2,y[np.abs(x-2).argmin()]),xytext=(1.7,1.1),arrowprops=dict(arrowstyle="->",color=RED),color=RED); ax.set(xlim=(.7,2.3),ylim=(-1.7,1.5),xlabel="x",ylabel="f(x)"); ax.grid(alpha=.25); fig_.tight_layout(); fig_.savefig(d/"q2_ivt_sign_change.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)
    # Q3 straight line log V vs t.
    t=np.linspace(0,6,100); fig_,ax=plt.subplots(figsize=(5,3),dpi=180); ax.plot(t,.05*t+2,color=BLUE,lw=2); ax.scatter([0,5],[2,2.25],color=RED,zorder=3); ax.annotate("(0, 2)",(0,2),xytext=(.45,1.96),color=RED); ax.annotate("(5, 2.25)",(5,2.25),xytext=(3.2,2.33),color=RED); ax.set(xlim=(-.2,6),ylim=(1.9,2.35),xlabel="t (years)",ylabel=r"$\log_{10}V$"); ax.grid(alpha=.25); fig_.tight_layout(); fig_.savefig(d/"q3_log_line.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)
    # Q4: parent and f(3x) state sequence on same axes.
    x=np.linspace(0,2*np.pi,500); f=lambda z:np.sqrt(3)*np.sin(2*z)-3*np.cos(2*z)
    fig_,ax=plt.subplots(figsize=(5,3),dpi=180); ax.axhline(0,color=INK,lw=.8); ax.plot(x,f(x),color=BLUE,lw=2); ax.set(xlim=(0,2*np.pi),ylim=(-4,4),xlabel="x",ylabel="f(x)",title="Step 1: original f(x)"); ax.grid(alpha=.25); fig_.tight_layout(); fig_.savefig(d/"q4_original_f.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)
    fig_,ax=plt.subplots(figsize=(5,3),dpi=180); ax.axhline(0,color=INK,lw=.8); ax.plot(x,f(x),color=GREY,lw=1.5,ls="--",label="previous f(x)"); ax.plot(x,f(3*x),color=RED,lw=2,label="current f(3x)"); ax.legend(fontsize=8); ax.set(xlim=(0,2*np.pi),ylim=(-4,4),xlabel="x",ylabel="value",title="Step 2: replace x by 3x (horizontal compression)"); ax.annotate("same amplitude; period ÷ 3",(1.2,2.7),color=RED,fontsize=8); ax.grid(alpha=.25); fig_.tight_layout(); fig_.savefig(d/"q4_f3x.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)
    # Q5 population model.
    t=np.linspace(0,35,500); N=4000*np.exp(.1*t)/(19+np.exp(.2*t)); T=np.log(19)/.2; M=4000*np.sqrt(19)/38
    fig_,ax=plt.subplots(figsize=(5,3),dpi=180); ax.plot(t,N,color=BLUE,lw=2); ax.scatter([T],[M],color=GREEN,zorder=3); ax.axvline(T,color=GREY,ls="--"); ax.annotate(r"maximum $\approx459$",(T,M),xytext=(T+2,370),arrowprops=dict(arrowstyle="->",color=GREEN),color=GREEN); ax.set(xlim=(0,35),ylim=(0,520),xlabel="t",ylabel="N squirrels"); ax.grid(alpha=.25); fig_.tight_layout(); fig_.savefig(d/"q5_population_maximum.png",bbox_inches="tight",facecolor="white"); plt.close(fig_)

def build():
    ROOT.mkdir(parents=True, exist_ok=True); (ROOT/"diagrams").mkdir(exist_ok=True)
    if not SRC_MJ.exists(): raise FileNotFoundError(SRC_MJ)
    shutil.copy2(SRC_MJ, ROOT/"mathjax-tex-svg.js")
    diagrams()
    esat = header("ESAT warm-up · sphere = 10 closed cylinders", "<strong>Problem (as read on the board).</strong> The surface area of a solid sphere of radius \\(R\\) equals the total surface area of <strong>10</strong> solid closed cylinders of radius \\(r\\) and height \\(h\\), with \\(h=4R\\). Find \\(R\\) in terms of \\(r\\).", 5, "Solved on board", "lesson-recording reconstruction")
    esat += part("Derive the surface-area equation",2,"\\(h=4R\\); a <em>closed</em> cylinder has two circular ends and one curved side.","<p class='strategy'>Separate the sphere from one complete cylinder before multiplying by 10.</p><p class='formula'><strong>Formula:</strong> sphere SA \\(=4\\pi R^2\\); closed-cylinder SA \\(=2\\pi r^2+2\\pi rh\\).</p><p><strong>Substitute:</strong> \\(4\\pi R^2=10(2\\pi r^2+2\\pi r h)\\).</p><p><strong>Then use:</strong> \\(h=4R\\), so \\(4\\pi R^2=10(2\\pi r^2+8\\pi rR)=20\\pi r^2+80\\pi rR\\).</p><p><strong>Sense check:</strong> both sides are areas, so every term has squared length units.</p>","<strong>Phuc's recorded slip:</strong> the first setup used only one circular end. A closed cylinder contributes <strong>two</strong> \\(\\pi r^2\\) ends.",fig("esat_surface_area.png","Sphere and closed-cylinder surface areas; the curved side unrolls to a rectangle."))
    esat += part("Solve for the physical radius",3,"From the setup: \\(4\\pi R^2=20\\pi r^2+80\\pi rR\\).","<p class='strategy'>Make a quadratic in \\(R\\), then retain the positive root because a radius is positive.</p><p>Divide by \\(4\\pi\\): \\(R^2=5r^2+20rR\\), hence \\(R^2-20rR-5r^2=0\\).</p><p class='formula'><strong>Formula:</strong> \\(R=\\frac{-b\\pm\\sqrt{b^2-4ac}}{2a}\\) with \\(a=1,b=-20r,c=-5r^2\\).</p><p>\\(R=\\frac{20r\\pm\\sqrt{400r^2+20r^2}}2=\\frac{20r\\pm2r\\sqrt{105}}2=r(10\\pm\\sqrt{105})\\).</p><p><strong>Final check:</strong> \\(10-\\sqrt{105}<0\\), so it cannot be a radius.</p><div class='answer'>\\(\\boxed{R=r(10+\\sqrt{105})}\\)</div>","<strong>Phuc's recorded slip:</strong> \\(\\pi r^2h\\) is cylinder <em>volume</em>, not surface area. Also retain the square in \\(4\\pi R^2\\).")
    esat += "<p class='footer'>Source class: lesson-taught warm-up. The option letters were not reliably captured in the evidence; this reconstruction records the derivation, not an option letter.</p>"
    write_card("ESAT_warmup", "ESAT warm-up", esat)

    q2 = header("P3 October 2025 · Q2 — IVT and iteration form", "<strong>From the paper.</strong> With \\(f(x)=\\dfrac{2x^2+3x-4}{e^x}-\\dfrac1{x^2},\\quad x\\in\\mathbb R,\\ x\\ne0\\), (a) show \\(f(x)=0\\) has a root \\(\\alpha\\in[1,2]\\); (b) show \\(f(x)=0\\) can be written as \\(x=\\sqrt[3]{\\dfrac{e^x+4x^2}{2x+3}}\\); (c) using \\(x_{n+1}=\\sqrt[3]{\\dfrac{e^{x_n}+4x_n^2}{2x_n+3}}\\) with \\(x_1=1\\), find \\(x_3\\) and \\(\\alpha\\) to 4 d.p.", 7, "Reviewed / prompted / deferred", "official-paper text in passed guide")
    q2 += part("Part (a) · establish a root",2,"\\(f(x)=\\dfrac{2x^2+3x-4}{e^x}-\\dfrac1{x^2}\\), on the whole interval \\([1,2]\\).","<p class='strategy'>Show a sign change at the stated endpoints, then state continuity on the closed interval.</p><p>\\(f(1)=\\dfrac1e-1=-0.6321\\ldots<0\\).</p><p>\\(f(2)=\\dfrac{10}{e^2}-\\dfrac14=1.1033\\ldots>0\\).</p><p>\\(f\\) is continuous on \\([1,2]\\) because neither denominator is zero there.</p><p><strong>Conclusion:</strong> by continuity and the sign change, \\(f(x)=0\\) has a root \\(\\alpha\\in[1,2]\\).</p><p><strong>Sense check:</strong> the plotted curve crosses the horizontal axis between the labelled endpoint signs.</p>","<strong>Harry's recorded correction:</strong> “The bit that everyone forgets is … continuity.” A sign change alone does not earn both marks.",fig("q2_ivt_sign_change.png","IVT visual: f(1) is negative and f(2) is positive, so continuity secures a crossing."))
    q2 += part("Part (b) · reach the cube-root form",2,"Start from \\(f(x)=0\\); target \\(x=\\sqrt[3]{\\dfrac{e^x+4x^2}{2x+3}}\\).","<p class='strategy'>Work towards the target denominator \\(2x+3\\) by exposing a factor of \\(x^3\\).</p><p>\\(\\dfrac{2x^2+3x-4}{e^x}=\\dfrac1{x^2}\\Rightarrow x^2(2x^2+3x-4)=e^x\\).</p><p>\\(2x^4+3x^3=e^x+4x^2\\Rightarrow x^3(2x+3)=e^x+4x^2\\).</p><p>\\(x^3=\\dfrac{e^x+4x^2}{2x+3}\\Rightarrow x=\\sqrt[3]{\\dfrac{e^x+4x^2}{2x+3}}\\).</p><p><strong>Sense check:</strong> cubing the target reproduces the isolated \\(x^3\\) equation.</p><div class='answer'>Target iteration form obtained.</div>","<strong>Evidence status:</strong> completed with prompting. The spoken transcript says the target was reached; the video ledger calls it partial. The passed guide preserves that source-status conflict.")
    q2 += part("Part (c) · deferred iteration",3,"Iteration rule and \\(x_1=1\\) are given in the question.","<p class='strategy'>This part was explicitly left in the lesson, so no tutor-attributed numerical iteration is supplied here.</p><p><strong>Independent-practice route:</strong> substitute \\(x_1\\) into the given recurrence to obtain \\(x_2\\), repeat for \\(x_3\\), and continue without rounding intermediate iterates until the displayed values stabilise.</p><p><strong>Sense check:</strong> any final \\(\\alpha\\) should remain in the IVT bracket \\([1,2]\\).</p>","<strong>Source boundary:</strong> Harry said “we'll leave that one”; part (c) was skipped/deferred, not a completed lesson solution.")
    q2 += "<p class='footer'>Source class: prior-paper review revisited in this lesson. Part (b) is reconstructed from the official-paper form and Harry's on-screen prompts; part (c) remains intentionally deferred.</p>"
    write_card("P3_Oct2025_Q2", "P3 October 2025 Q2", q2)

    q3 = header("P3 October 2025 · Q3 — linearise, exponentiate, differentiate", "<strong>From the paper.</strong> The share price £\\(V\\) is monitored; a graph of \\(\\log_{10}V\\) against \\(t\\) (years) is a straight line through \\((0,2)\\) and \\((5,2.25)\\). (a) find \\(\\log_{10}V=mt+c\\); (b) write as \\(V=ab^t\\) (exact \\(a\\), \\(b\\) to 3 s.f.); (c) when \\(t=T\\) the rate of increase is £50/yr — find \\(T\\) to the nearest integer. <em>Solutions relying entirely on calculator technology are not acceptable.</em>", 9, "Solved", "official-paper text in passed guide")
    q3 += part("Part (a) · equation of the line",2,"Vertical variable is \\(\\log_{10}V\\); points \\((0,2)\\), \\((5,2.25)\\).","<p class='strategy'>Read “\\(\\log_{10}V\\) against \\(t\\)” as y against x, then find gradient and intercept.</p><p>\\(m=\\dfrac{2.25-2}{5-0}=0.05\\), and \\(c=2\\).</p><p>\\(\\log_{10}V-2=0.05(t-0)\\).</p><div class='answer'>\\(\\boxed{\\log_{10}V=0.05t+2}\\)</div><p><strong>Sense check:</strong> at \\(t=5\\), the model returns \\(2.25\\).</p>","<strong>Phuc's recorded slip:</strong> the vertical axis was initially named \\(V\\), not \\(\\log_{10}V\\).",fig("q3_log_line.png","The supplied straight-line graph with the two exact points."))
    q3 += part("Part (b) · undo the logarithm",3,"\\(\\log_{10}V=0.05t+2\\); requested form \\(V=ab^t\\).","<p class='strategy'>Raise 10 to both sides and split the exponent before identifying \\(a\\) and \\(b\\).</p><p>\\(V=10^{0.05t+2}=10^2\\cdot10^{0.05t}=100(10^{0.05})^t\\).</p><p>Thus \\(a=100\\) exactly and \\(b=10^{0.05}=1.12201\\ldots=1.12\\) to 3 s.f.</p><p><strong>Sense check:</strong> at \\(t=0\\), this gives \\(V=100\\), consistent with \\(\\log_{10}V=2\\).</p><div class='answer'>\\(\\boxed{V=100(10^{0.05})^t;\\ a=100,\\ b=1.12\\text{ (3 s.f.)}}\\)</div>","<strong>Harry's recorded correction:</strong> rewrite \\(10^{0.05t}=(10^{0.05})^t\\); do not leave the exponent in a form that hides \\(b^t\\).")
    q3 += part("Part (c) · rate of increase",4,"Use the <em>exact</em> model \\(V=100\\cdot10^{0.05t}\\), not the rounded base \\(1.12\\).","<p class='strategy'>“Rate” means differentiate. Keep the exact base throughout and set the derivative to positive 50.</p><p class='formula'><strong>Formula:</strong> \\(\\dfrac{d}{dt}a^{kt}=a^{kt}k\\ln a\\).</p><p>\\(\\dfrac{dV}{dt}=100\\cdot10^{0.05t}(0.05\\ln10)\\).</p><p>Set \\(100\\cdot10^{0.05T}(0.05\\ln10)=50\\), giving \\(10^{0.05T}=\\dfrac{10}{\\ln10}\\).</p><p>\\(T=\\dfrac{\\log_{10}(10/\\ln10)}{0.05}=12.755686\\ldots\\).</p><p><strong>Sense check:</strong> only the final requested integer is rounded.</p><div class='answer'>\\(\\boxed{T=13}\\)</div>","<strong>Phuc's recorded slip:</strong> “arithmetic series” was suggested for a rate. Harry's cue was: rate \\(\\Rightarrow\\) differentiate; an increase means \\(+50\\), not \\(-50\\).")
    q3 += "<p class='footer'>Source class: lesson-taught prior-paper review. Arithmetic uses the passed-guide correction: differentiating rounded \\(1.12^t\\) is not an exact method.</p>"
    write_card("P3_Oct2025_Q3", "P3 October 2025 Q3", q3)

    q4 = header("P3 October 2025 · Q4 — R-form and a minimum", "<strong>From the paper.</strong> (a) Express \\(f(x)=\\sqrt3\\sin2x-3\\cos2x\\) in the form \\(R\\sin(2x-\\alpha)\\), with \\(R>0\\) and \\(0<\\alpha<\\tfrac\\pi2\\); give exact \\(R\\) and \\(\\alpha\\). (b) For \\(g(x)=\\dfrac{18}{f(3x)+4\\sqrt3}\\ (x>0)\\): (i) write down the exact minimum of \\(g(x)\\); (ii) find the smallest \\(x\\) at which it occurs. <em>Show all stages of working.</em>", 6, "Solved", "official-paper text in passed guide")
    q4 += part("Part (a) · exact R-form",3,"\\(f(x)=\\sqrt3\\sin2x-3\\cos2x\\); target \\(R\\sin(2x-\\alpha)\\).","<p class='strategy'>Expand the target, equate coefficients, then divide for \\(\\tan\\alpha\\) and square-and-add for exact \\(R\\).</p><p>\\(R\\sin(2x-\\alpha)=R\\cos\\alpha\\sin2x-R\\sin\\alpha\\cos2x\\).</p><p>So \\(R\\cos\\alpha=\\sqrt3\\), \\(R\\sin\\alpha=3\\).</p><p>\\(\\tan\\alpha=\\dfrac3{\\sqrt3}=\\sqrt3\\Rightarrow\\alpha=\\tfrac\\pi3\\).</p><p>\\(R^2=3+9=12\\Rightarrow R=2\\sqrt3\\).</p><p><strong>Sense check:</strong> \\(\\alpha=\\pi/3\\) lies in the required first-quadrant range.</p><div class='answer'>\\(\\boxed{f(x)=2\\sqrt3\\sin(2x-\\tfrac\\pi3)}\\)</div>","<strong>Harry's recorded warning:</strong> using a decimal \\(\\alpha\\) to find \\(R\\) is “quite dangerous” in an exact-value question. Use square-and-add.",fig("q4_original_f.png","Step 1: the original R-form curve; blue represents the current starting function."))
    q4 += part("Part (b)(i)–(ii) · minimum and smallest x",3,"\\(f(x)=2\\sqrt3\\sin(2x-\\tfrac\\pi3)\\); therefore \\(f(3x)=2\\sqrt3\\sin(6x-\\tfrac\\pi3)\\).","<p class='strategy'>A fixed positive numerator gives the smallest fraction when its denominator is largest.</p><p>\\(g(x)=\\dfrac{18}{2\\sqrt3\\sin(6x-\\tfrac\\pi3)+4\\sqrt3}\\).</p><p>Maximum denominator: \\(2\\sqrt3(1)+4\\sqrt3=6\\sqrt3\\).</p><p>\\(\\min g=\\dfrac{18}{6\\sqrt3}=\\dfrac3{\\sqrt3}=\\sqrt3\\).</p><p><strong>Sense check:</strong> the sine value cannot exceed 1, so this is the largest possible denominator.</p><div class='answer'>\\(\\boxed{\\min g(x)=\\sqrt3}\\)</div>","<strong>Common trap:</strong> minimise a positive fraction by maximising its denominator; do not minimise the denominator.",fig("q4_f3x.png","Step 2: f(3x) is horizontally compressed; grey dashed is f(x), red is the current f(3x)."))
    q4 += part("Part (b)(ii) · smallest x",None,"Minimum requires \\(\\sin(6x-\\tfrac\\pi3)=1\\); \\(x>0\\).","<p class='strategy'>Set the sine angle to its first maximum and solve in radians.</p><p>\\(6x-\\tfrac\\pi3=\\tfrac\\pi2\\).</p><p>\\(6x=\\tfrac\\pi2+\\tfrac\\pi3=\\tfrac{5\\pi}6\\).</p><p>\\(x=\\tfrac{5\\pi}{36}\\).</p><p><strong>Sense check:</strong> adding \\(2\\pi\\) gives the next solution, which is larger.</p><div class='answer'>\\(\\boxed{x=\\tfrac{5\\pi}{36}}\\)</div>","<strong>Harry's recorded correction:</strong> use \\(\\tan^{-1}\\), not \\(\\sin^{-1}\\), for \\(\\alpha\\); keep the calculator in radians.")
    q4 += "<p class='footer'>Source class: lesson-taught prior-paper review. The passed guide resolves the conflicting R=5 transcription in favour of the official-paper expression used here.</p>"
    write_card("P3_Oct2025_Q4", "P3 October 2025 Q4", q4)

    q5 = header("P3 October 2025 · Q5 — squirrels model and maximum", "<strong>From the paper.</strong> \\(N=\\dfrac{4000e^{0.1t}}{19+e^{0.2t}},\\quad t\\ge0\\). Use the equation of the model to answer parts (a), (b), (c) and (d). (a) Find the number of squirrels at the start of the study. (b) Find \\(\\dfrac{dN}{dt}\\). (c) At the maximum \\(t=T\\), show \\(e^{0.2T}=A\\) (find \\(A\\)). (d) Find the maximum number of squirrels, to the nearest whole number. <em>Show all stages of working.</em>", 8, "Solved", "official-paper text in passed guide")
    q5 += part("Part (a) · start of the study",1,"\\(t=0\\); \\(e^0=1\\).","<p class='strategy'>Substitute the initial time exactly before simplifying.</p><p>\\(N=\\dfrac{4000e^0}{19+e^0}=\\dfrac{4000}{20}=200\\).</p><p><strong>Sense check:</strong> the denominator is \\(19+1\\), not 19.</p><div class='answer'>\\(\\boxed{200\\text{ squirrels}}\\)</div>","<strong>Phuc's recorded slip:</strong> the \\(+1\\) in the denominator was lost. \\(e^0=1\\).")
    q5 += part("Part (b) · quotient rule",2,"\\(u=4000e^{0.1t}\\), \\(v=19+e^{0.2t}\\); \\(N=u/v\\).","<p class='strategy'>Use the formula-book quotient rule and preserve the subtraction.</p><p class='formula'><strong>Formula:</strong> \\(\\left(\\dfrac uv\\right)'=\\dfrac{vu'-uv'}{v^2}\\).</p><p>\\(u'=400e^{0.1t}\\), \\(v'=0.2e^{0.2t}\\).</p><p>\\(\\dfrac{dN}{dt}=\\dfrac{(19+e^{0.2t})(400e^{0.1t})-(4000e^{0.1t})(0.2e^{0.2t})}{(19+e^{0.2t})^2}\\).</p><p>\\(=\\dfrac{7600e^{0.1t}-400e^{0.3t}}{(19+e^{0.2t})^2}\\).</p><p><strong>Sense check:</strong> \\(e^{0.1t}e^{0.2t}=e^{0.3t}\\).</p><div class='answer'>\\(\\boxed{\\dfrac{dN}{dt}=\\dfrac{7600e^{0.1t}-400e^{0.3t}}{(19+e^{0.2t})^2}}\\)</div>","<strong>Phuc's recorded slip:</strong> the minus sign in the quotient-rule numerator was dropped. Keep \\(vu'-uv'\\) visible.")
    q5 += part("Part (c) · stationary condition",2,"From part (b), denominator \\((19+e^{0.2T})^2\\) is always positive.","<p class='strategy'>At a maximum, set the derivative to zero; only the numerator can be zero.</p><p>\\(7600e^{0.1T}-400e^{0.3T}=0\\).</p><p>\\(e^{0.1T}(7600-400e^{0.2T})=0\\).</p><p>Since \\(e^{0.1T}>0\\), \\(7600-400e^{0.2T}=0\\), so \\(e^{0.2T}=19\\).</p><p><strong>Sense check:</strong> exponential values never equal zero.</p><div class='answer'>\\(\\boxed{A=19}\\)</div>","<strong>Phuc's recorded correction:</strong> this is a “show that” part: stop at \\(e^{0.2T}=19\\); do not solve \\(T\\) yet.")
    q5 += part("Part (d) · maximum number",3,"\\(e^{0.2T}=19\\), so \\(e^{0.1T}=\\sqrt{19}\\); do not round \\(T\\) before substitution.","<p class='strategy'>Use the exact stationary relation directly in the model; it avoids rounding \\(T\\).</p><p>\\(N=\\dfrac{4000\\sqrt{19}}{19+19}=\\dfrac{4000\\sqrt{19}}{38}=458.831467\\ldots\\).</p><p><strong>Final check:</strong> round only the requested final population.</p><div class='answer'>\\(\\boxed{459\\text{ squirrels}}\\)</div>","<strong>Evidence reconciliation:</strong> the passed guide flags a ledger reading of “959” and an incorrect denominator. The official model plus Harry's spoken “459 is fine” support 459.",fig("q5_population_maximum.png","Population curve from the stated model; green marks the stationary maximum near 459."))
    q5 += "<p class='footer'>Source class: lesson-taught prior-paper review. The maximum uses the passed guide's checked value \\(4000\\sqrt{19}/38=458.831467\\ldots\\).</p>"
    write_card("P3_Oct2025_Q5", "P3 October 2025 Q5", q5)

    tiles = [("ESAT_warmup","ESAT warm-up","Solved on board","Sphere = 10 closed cylinders"),("P3_Oct2025_Q2","P3 Q2","Reviewed / prompted / deferred","IVT and iteration form"),("P3_Oct2025_Q3","P3 Q3","Solved","Linearise, exponentiate, differentiate"),("P3_Oct2025_Q4","P3 Q4","Solved","Exact R-form and a minimum"),("P3_Oct2025_Q5","P3 Q5","Solved","Squirrels model and maximum")]
    tile_html="".join(f'<a class="tile" href="{s}.html"><img src="{s}.png" alt="Preview of {t}"><div><span>{status}</span><h2>{t}</h2><p>{desc}</p></div></a>' for s,t,status,desc in tiles)
    landing=f'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Harry P3 October 2025 + ESAT · multi-step v2</title><style>:root{{--ink:#111827;--muted:#64748b;--paper:#fff;--canvas:#f3f5f8;--accent:#0f766e;--line:#d8dee8}}*{{box-sizing:border-box}}body{{margin:0;background:var(--canvas);font:15px/1.5 -apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;color:var(--ink)}}main{{max-width:1120px;margin:auto;padding:44px 24px}}.eyebrow{{color:var(--accent);font-size:11px;font-weight:800;letter-spacing:.12em;text-transform:uppercase}}h1{{font-size:clamp(28px,5vw,44px);letter-spacing:-.04em;line-height:1.05;margin:8px 0 12px}}.lead{{max-width:760px;color:var(--muted)}}.notice{{margin:24px 0;padding:13px 15px;border-left:4px solid var(--accent);background:#e7f5f2;border-radius:8px}}.grid{{display:grid;grid-template-columns:repeat(auto-fit,minmax(290px,1fr));gap:18px}}.tile{{background:var(--paper);border:1px solid var(--line);border-radius:13px;overflow:hidden;color:inherit;text-decoration:none;box-shadow:0 1px 2px #1111;transition:transform .15s,box-shadow .15s}}.tile:hover{{transform:translateY(-2px);box-shadow:0 7px 18px #1112}}.tile img{{width:100%;height:190px;object-fit:cover;object-position:top;border-bottom:1px solid var(--line);display:block}}.tile div{{padding:14px 16px}}.tile span{{font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.06em;color:var(--accent)}}.tile h2{{font-size:20px;margin:4px 0}}.tile p{{margin:0;color:var(--muted)}}footer{{margin-top:28px;padding-top:14px;border-top:1px solid var(--line);font-size:12px;color:var(--muted)}}@media(max-width:600px){{main{{padding:28px 15px}}.tile img{{height:150px}}}}</style></head><body><main><div class="eyebrow">Harry → Phuc · 11 July 2026</div><h1>P3 October 2025 + ESAT<br>multi-step deck</h1><p class="lead">Five source-bounded, maskable working cards rebuilt to the current multi-step format. Each opens as a standalone card and includes a pre-rendered PNG export.</p><div class="notice"><strong>Scope boundary.</strong> P3 Q1 is deliberately not included: the passed guide says it was discussed only and does not preserve a complete verbatim prompt for an exact standalone card. P3 Q6–Q9 were not discussed in the lesson. This local v2 pack does not claim independent review or publication.</div><section class="grid">{tile_html}</section><footer>Guide provenance: <code>harry_2026-07-11_p3_esat_revision_guide.tex</code> · 11 July lesson evidence. Source status is shown inside each card. Local-only deterministic self-QA accompanies this pack.</footer></main></body></html>'''
    (ROOT/"index.html").write_text(landing,encoding="utf-8")

if __name__ == "__main__": build()
